import { Alert, Button, Descriptions, type FormInstance, Flex, Tag, Typography } from 'antd';
import { useState } from 'react';

import type { ResultStatus } from '../../api/runs';
import { type CheckDryRunResult, dryRunCheck, targetString } from '../../api/suites';
import { RESULT_STATUS_COLORS } from '../results/resultsFormat';
import { ScalarValue } from '../results/ScalarValue';
import { buildCheckPayload } from './checkForm';

/**
 * Inline "preview before saving" affordance for the check editor: runs the
 * in-progress check against the suite's live target via the dry-run API
 * (`POST /suites/{id}/checks/dryrun`) and shows the severity outcome — without
 * persisting a Run/Result. Shared by the create page (`CheckNew`) and the edit
 * page (`CheckEdit`); both pass the suite's run target (#215) so the same
 * `table`/`schema` the run would use is previewed.
 *
 * v1 backend limits (surfaced as the API's error message): dry-run needs a
 * table target and a Snowflake connection. The button is disabled (with a
 * reason) until an expectation is picked and the suite has a table target;
 * everything else (no credential, unreachable warehouse, wrong datasource) comes
 * back as a clean error from the API and renders in the alert.
 */
export function DryRunPreview({
  suiteId,
  expectationType,
  target,
  form,
}: {
  suiteId: string;
  expectationType: string | undefined;
  target: Record<string, unknown> | null;
  form: FormInstance;
}) {
  const [state, setState] = useState<
    | { status: 'idle' }
    | { status: 'running' }
    | { status: 'ok'; result: CheckDryRunResult }
    | { status: 'error'; error: string }
  >({ status: 'idle' });

  // Clear a previous preview when the expectation changes — on the edit page
  // the picker switches type in-place (DryRunPreview stays mounted), so without
  // this the old result would linger, misattributed to the new expectation.
  // Render-phase reset (React's "adjust state when a prop changes" pattern)
  // rather than an effect, so the stale result never paints.
  const [prevExpectation, setPrevExpectation] = useState(expectationType);
  if (expectationType !== prevExpectation) {
    setPrevExpectation(expectationType);
    setState({ status: 'idle' });
  }

  const table = targetString(target, 'table');
  const schema = targetString(target, 'schema') ?? null;

  const disabledReason = !expectationType
    ? 'Pick an expectation to preview it.'
    : !table
      ? 'Set a table target on the suite to preview against live data.'
      : undefined;

  const run = async () => {
    if (!expectationType || !table) return;
    setState({ status: 'running' });
    try {
      // Reuse the create/update payload shaping so the preview runs exactly the
      // config (and thresholds) the saved check would — name is irrelevant here.
      const payload = buildCheckPayload({
        ...form.getFieldsValue(true),
        expectation_type: expectationType,
      });
      const result = await dryRunCheck(suiteId, {
        expectation_type: expectationType,
        config: payload.config,
        warn_threshold: payload.warn_threshold,
        fail_threshold: payload.fail_threshold,
        critical_threshold: payload.critical_threshold,
        table,
        schema,
      });
      setState({ status: 'ok', result });
    } catch (err) {
      setState({ status: 'error', error: err instanceof Error ? err.message : 'unknown error' });
    }
  };

  return (
    <Flex vertical gap={8}>
      <Flex gap={12} align="center">
        <Button onClick={run} loading={state.status === 'running'} disabled={!!disabledReason}>
          Dry-run preview
        </Button>
        {disabledReason && <Typography.Text type="secondary">{disabledReason}</Typography.Text>}
      </Flex>
      {state.status === 'ok' && <DryRunResultView result={state.result} />}
      {state.status === 'error' && (
        <Alert type="error" showIcon title="Dry-run failed" description={state.error} />
      )}
    </Flex>
  );
}

function DryRunResultView({ result }: { result: CheckDryRunResult }) {
  return (
    <Descriptions
      size="small"
      bordered
      column={1}
      styles={{ label: { width: 140 } }}
      items={[
        {
          key: 'status',
          label: 'Result',
          children: (
            <Tag color={RESULT_STATUS_COLORS[result.status as ResultStatus]}>{result.status}</Tag>
          ),
        },
        {
          key: 'metric',
          label: 'Metric',
          children: result.metric_value === null ? '—' : result.metric_value,
        },
        {
          key: 'observed',
          label: 'Observed',
          children: <ScalarValue value={result.observed_value} />,
        },
        {
          key: 'expected',
          label: 'Expected',
          children: <ScalarValue value={result.expected_value} />,
        },
      ]}
    />
  );
}

def resolve_target(conn_type: str, target: dict[str, Any] | None) -> ResolvedTarget:
    """Resolve ``target`` for a ``conn_type`` connection, or raise (422).

    Raises `SuiteTargetInvalidError` if the suite is targetless, the target is
    missing the field its datasource requires (`path` for flat files, `table`
    for SQL, `catalog` for Unity Catalog), or the connection type has no run path
    (orchestration providers — they are never suite datasources).
    """
    if not target:
        raise SuiteTargetInvalidError(
            "suite has no target configured", detail={"connection_type": conn_type}
        )

    if conn_type in _FLATFILE_TYPES:
        # A batch target (regex `pattern`) is resolved to a concrete path at run
        # time; a literal target carries the `path` directly. The two are mutually
        # exclusive — both set is an ambiguous target, not a silent batch win.
        if "pattern" in target and target.get("path"):
            raise SuiteTargetInvalidError(
                "flat-file target is ambiguous: set either 'path' (literal) or "
                "'pattern' (batch), not both",
                detail={"connection_type": conn_type},
            )
        if "pattern" in target:
            return ResolvedTarget(
                table="", schema=None, catalog=None, batch=_batch_spec(target, conn_type)
            )
        path = _require(target, "path", conn_type)
        return ResolvedTarget(table=path, schema=None, catalog=None)

    if conn_type == "snowflake":
        table = _require(target, "table", conn_type)
        return ResolvedTarget(table=table, schema=_str_or_none(target.get("schema")), catalog=None)

    if conn_type == "unity_catalog":
        table = _require(target, "table", conn_type)
        catalog = _require(target, "catalog", conn_type)
        return ResolvedTarget(
            table=table, schema=_str_or_none(target.get("schema")), catalog=catalog
        )

    raise SuiteTargetInvalidError(
        f"connection type {conn_type!r} has no run path (not a datasource)",
        detail={"connection_type": conn_type},
    )


def validate_target(conn_type: str, target: dict[str, Any]) -> None:
    """Write-time guard: a non-null target must resolve for its datasource.

    Reuses `resolve_target`'s rules so a target saved on a suite is always
    runnable. Callers only invoke this when a target is *provided* — a suite may
